"use strict";
const Commons = require("../utils/commons");
const RequestUtils = require("../utils/requestUtils");
async function getTransactionStatus(apiKey, reference) {
    const statusResponse = await RequestUtils.sendRequestTo(Commons.serverBaseUrl() + '/status/' + reference + '?apikey=' + apiKey, {}, null, 'get', true);
    if (statusResponse.response.error && statusResponse.response.error.msg) {
        return {
            success: false,
            message: statusResponse.response.error.msg,
            transaction: { statusMessageCode: statusResponse.status.code },
        };
    }
    if (statusResponse.response.error) {
        return {
            success: false,
            message: 'error',
            transaction: { statusMessageCode: statusResponse.status.code },
        };
    }
    if (!/^2../.test(statusResponse.status.code)) {
        return Object.assign(Object.assign({ success: false, message: 'error' }, statusResponse.response), { transaction: Object.assign(Object.assign({}, (statusResponse.response.transaction || {})), { statusMessageCode: statusResponse.status.code }) });
    }
    delete statusResponse.response.transaction.checkoutUrl;
    delete statusResponse.response.transaction.successRedirectionUrl;
    delete statusResponse.response.transaction.errorRedirectionUrl;
    return statusResponse.response;
}
module.exports = getTransactionStatus;
